sql:
SELECT MIN(popularity_rank) AS lowest_popularity_rank
FROM baby_names
WHERE year = 2020 AND state_code = 'CA';

external_knowledge:
- 'recent year' refers to the year 2020;
- 'best-received' indicates the highest ratings given by users;
- The rating is on a user scale, typically from 1 to 5 stars.

sql:
SELECT name
FROM baby_names
WHERE gender = 'Male';

SELECT name 
FROM baby_names 
WHERE name_id NOT IN (SELECT name_id FROM name_variants);

SELECT name_id, year_id, popularity_score, relative_popularity
FROM popularity_trends
ORDER BY popularity_score DESC;

SELECT name 
FROM baby_names 
WHERE gender = 'F' OR gender = 'M';

external_knowledge:
- "shining stars over the golden state" refers metaphorically to the baby names selected for California;
- "their lights vary across the regions and genders through the years" indicates that the names, regions, genders, and years are considered;
- "brilliance shines brighter than the common 10,000 threshold" metaphorically refers to the condition that the average popularity score is greater than 10,000;
- The "brightness" of the names is metaphorically compared to their popularity scores.

- "wandered into the shadows of popularity" metaphorically refers to names with a popularity rank greater than 500; 
- "midstream in the wide river of names" symbolically represents the middle range of name popularity, implying that names with a high rank are less popular;
- "golden state" is a nickname for California;
- "year 2000" refers to the specific year being queried.

sql:
SELECT DISTINCT b.name, b.name_meaning, b.name_origin
FROM baby_names b
WHERE b.year = 2020;

SELECT name, gender, AVG(popularity_rank) AS Average_Popularity_Rank
FROM baby_names
GROUP BY name, gender;

SELECT name, gender, year
FROM baby_names
WHERE cultural_significance = 'Biblical';
